using Microsoft.EntityFrameworkCore;
using NguyenHoangNgocChauBusinessObjects.Data;
using NguyenHoangNgocChauBusinessObjects.Models;
namespace NguyenHoangNgocChauBusinessObjects.DAO;
public class AccountDAO(FUNewsManagementContext db) { public Task<SystemAccount?> FindLoginAsync(string email,string password)=>db.SystemAccounts.FirstOrDefaultAsync(x=>x.AccountEmail==email&&x.AccountPassword==password); public Task<List<SystemAccount>> SearchAsync(string? q)=>db.SystemAccounts.Where(x=>string.IsNullOrEmpty(q)||x.AccountName.Contains(q)||x.AccountEmail.Contains(q)||(x.AccountRole??0).ToString()==q).OrderBy(x=>x.AccountName).ToListAsync(); public Task<SystemAccount?> GetAsync(short id)=>db.SystemAccounts.FindAsync(id).AsTask(); public Task<bool> EmailExistsAsync(string email,short? excludeId)=>db.SystemAccounts.AnyAsync(x=>x.AccountEmail.ToUpper()==email.ToUpper()&&(!excludeId.HasValue||x.AccountId!=excludeId.Value)); public async Task SaveAsync(SystemAccount x,bool add){if(add){var maxId=await db.SystemAccounts.Select(a=>(short?)a.AccountId).MaxAsync()??0;x.AccountId=checked((short)(maxId+1));db.Add(x);}else db.Update(x);await db.SaveChangesAsync();} public async Task<bool> DeleteAsync(short id){if(await db.NewsArticles.AnyAsync(x=>x.CreatedById==id||x.UpdatedById==id))return false;var x=await GetAsync(id);if(x is null)return true;try{db.Remove(x);await db.SaveChangesAsync();return true;}catch(DbUpdateException){return false;}} }
public class CategoryDAO(FUNewsManagementContext db) { public Task<List<Category>> SearchAsync(string? q)=>db.Categories.Where(x=>string.IsNullOrEmpty(q)||x.CategoryName.Contains(q)||(x.CategoryDescription??"").Contains(q)).OrderBy(x=>x.CategoryName).ToListAsync(); public Task<Category?> GetAsync(short id)=>db.Categories.FindAsync(id).AsTask(); public async Task SaveAsync(Category x,bool add){if(add)db.Add(x);else db.Update(x);await db.SaveChangesAsync();} public async Task<bool> DeleteAsync(short id){if(await db.NewsArticles.AnyAsync(x=>x.CategoryId==id))return false;var x=await GetAsync(id);if(x!=null){db.Remove(x);await db.SaveChangesAsync();}return true;} }
public class TagDAO(FUNewsManagementContext db) { public Task<List<Tag>> GetAllAsync()=>db.Tags.OrderBy(x=>x.TagName).ToListAsync(); }
public class NewsDAO(FUNewsManagementContext db) { public Task<List<NewsArticle>> SearchAsync(string? q,bool activeOnly)=>db.NewsArticles.Include(x=>x.Category).Include(x=>x.CreatedBy).Include(x=>x.NewsTags).ThenInclude(x=>x.Tag).Where(x=>(!activeOnly||x.NewsStatus==true)&&(string.IsNullOrEmpty(q)||x.NewsTitle.Contains(q)||x.Headline.Contains(q)||x.NewsContent.Contains(q)||x.NewsSource.Contains(q))).OrderByDescending(x=>x.CreatedDate).ToListAsync(); public Task<NewsArticle?> GetAsync(string id)=>db.NewsArticles.Include(x=>x.Category).Include(x=>x.CreatedBy).Include(x=>x.NewsTags).ThenInclude(x=>x.Tag).FirstOrDefaultAsync(x=>x.NewsArticleId==id); public async Task SaveAsync(NewsArticle x,IEnumerable<int> tags,bool add){if(add)db.Add(x);else{db.Update(x);db.NewsTags.RemoveRange(db.NewsTags.Where(t=>t.NewsArticleId==x.NewsArticleId));}foreach(var tag in tags.Distinct())db.NewsTags.Add(new NewsTag{NewsArticleId=x.NewsArticleId,TagId=tag});await db.SaveChangesAsync();} public async Task DeleteAsync(string id){var x=await GetAsync(id);if(x!=null){db.Remove(x);await db.SaveChangesAsync();}} public Task<List<NewsArticle>> ReportAsync(DateTime from,DateTime to)=>db.NewsArticles.Include(x=>x.Category).Include(x=>x.CreatedBy).Where(x=>x.CreatedDate>=from&&x.CreatedDate<to.Date.AddDays(1)).OrderByDescending(x=>x.CreatedDate).ToListAsync(); }
